# Type Inference in Zod

Zod's type inference lets you define a schema once and derive the TypeScript type from it — no duplication, no drift.

## z.infer<typeof schema>

```typescript
import { z } from "zod";

const UserSchema = z.object({
  id: z.string().uuid(),
  name: z.string().min(1),
  email: z.string().email(),
  age: z.number().int().positive().optional(),
  role: z.enum(["admin", "user", "guest"]),
  tags: z.array(z.string()).default([]),
});

// Extract the type
type User = z.infer<typeof UserSchema>;
// {
//   id: string;
//   name: string;
//   email: string;
//   age?: number | undefined;
//   role: "admin" | "user" | "guest";
//   tags: string[];
// }

// Use the type everywhere
function processUser(user: User) { /* ... */ }
const users: User[] = [];
```

## z.input vs z.output

When a schema has transforms, `.default()`, or `.catch()`, the input and output types differ:

```typescript
const FormSchema = z.object({
  name: z.string().min(1),
  age: z.string().transform((s) => parseInt(s, 10)),
  newsletter: z.boolean().default(false),
  createdAt: z.date().default(() => new Date()),
});

// Input type — what you pass to .parse()
type FormInput = z.input<typeof FormSchema>;
// {
//   name: string;
//   age: string;                    ← before transform
//   newsletter?: boolean | undefined;  ← before default
//   createdAt?: Date | undefined;      ← before default
// }

// Output type — what .parse() returns
type FormOutput = z.output<typeof FormSchema>;
// {
//   name: string;
//   age: number;      ← after transform
//   newsletter: boolean; ← after default
//   createdAt: Date;     ← after default
// }

// z.infer is always the OUTPUT type
type FormData = z.infer<typeof FormSchema>; // same as FormOutput
```

## Pattern: Schema-First Design

```typescript
// 1. Define the schema (single source of truth)
const CreateUserSchema = z.object({
  name: z.string().min(1).max(100),
  email: z.string().email(),
  password: z.string().min(8),
});

// 2. Infer the type
type CreateUserInput = z.infer<typeof CreateUserSchema>;

// 3. Use everywhere: API handlers, service functions, tests
async function createUser(input: CreateUserInput) {
  // input is fully typed — { name: string; email: string; password: string }
}

// 4. Validate at the boundary
app.post("/users", (req, res) => {
  const result = CreateUserSchema.safeParse(req.body);
  if (!result.success) return res.status(400).json(result.error.flatten());
  createUser(result.data); // result.data is CreateUserInput
});
```

## Recursive Type Inference

```typescript
// For recursive schemas, you must annotate the type explicitly
interface Category {
  name: string;
  subcategories: Category[];
}

const CategorySchema: z.ZodType<Category> = z.object({
  name: z.string(),
  subcategories: z.lazy(() => CategorySchema.array()),
});

// z.infer<typeof CategorySchema> won't work for recursive types
// Use the explicit interface instead
type Category = z.infer<typeof CategorySchema>; // ✗ circular
// Use: type Category = Category; (the interface above)
```

## Inference with Generics

```typescript
// Accept any Zod schema as a generic parameter
function validate<T extends z.ZodTypeAny>(schema: T, data: unknown): z.infer<T> {
  return schema.parse(data);
}

// The return type is inferred from the schema
const user = validate(UserSchema, rawData); // type: User
const num = validate(z.number(), rawInput); // type: number

// Constrain generic to specific shapes
function validateObject<T extends z.ZodObject<z.ZodRawShape>>(
  schema: T,
  data: unknown
): z.infer<T> {
  return schema.parse(data);
}
```

## Utility Types

```typescript
// z.ZodTypeAny — the base type for all Zod schemas
type AnySchema = z.ZodTypeAny;

// z.ZodType<Output, Def, Input> — parameterized schema type
type StringSchema = z.ZodType<string>;

// z.ZodObject<Shape> — object schema with known shape
type UserObjectSchema = z.ZodObject<typeof UserSchema.shape>;

// z.ZodRawShape — the shape parameter type
type Shape = z.ZodRawShape; // { [k: string]: z.ZodTypeAny }
```
